{
  "name": "Study Quest",
  "description": "A gamified pixel-art study companion inspired by Codédex. Features a Pomodoro timer, AI-powered study guide, quest-based to-do list, and total study time tracking.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Task {
  id: string;
  text: string;
  completed: boolean;
  xp: number;
}

export interface StudySession {
  date: string;
  durationMinutes: number;
}

export interface UserStats {
  level: number;
  xp: number;
  totalMinutes: number;
  gold: number;
}

export type View = 'home' | 'tasks' | 'timer' | 'stats' | 'ai';

import React, { useState, useEffect } from 'react';
import { Hero } from './components/Hero';
import { Navbar } from './components/Navbar';
import { TodoList } from './components/TodoList';
import { Pomodoro } from './components/Pomodoro';
import { Statistics } from './components/Statistics';
import { AISuggestions } from './components/AISuggestions';
import { Task, UserStats, View } from './types';

const App: React.FC = () => {
  const [view, setView] = useState<View>('home');
  const [tasks, setTasks] = useState<Task[]>(() => {
    const saved = localStorage.getItem('quest_tasks');
    return saved ? JSON.parse(saved) : [];
  });

  const [stats, setStats] = useState<UserStats>(() => {
    const saved = localStorage.getItem('quest_stats');
    return saved ? JSON.parse(saved) : { level: 1, xp: 0, totalMinutes: 0, gold: 50 };
  });

  useEffect(() => {
    localStorage.setItem('quest_tasks', JSON.stringify(tasks));
  }, [tasks]);

  useEffect(() => {
    localStorage.setItem('quest_stats', JSON.stringify(stats));
  }, [stats]);

  const addMinutes = (minutes: number) => {
    setStats(prev => {
      const newMinutes = prev.totalMinutes + minutes;
      const gainedXP = Math.floor(minutes * 5);
      const newXP = prev.xp + gainedXP;
      const newLevel = Math.floor(newXP / 1000) + 1;

      return {
        ...prev,
        totalMinutes: newMinutes,
        xp: newXP,
        level: newLevel,
        gold: prev.gold + Math.floor(minutes / 5)
      };
    });
  };

  const handleTaskToggle = (id: string) => {
    setTasks(prev => prev.map(t => {
      if (t.id === id) {
        if (!t.completed) {
          // Reward XP/Gold on completion
          setStats(s => ({ ...s, xp: s.xp + t.xp, gold: s.gold + 10 }));
        }
        return { ...t, completed: !t.completed };
      }
      return t;
    }));
  };

  const renderView = () => {
    switch (view) {
      case 'home': return <Hero onStart={() => setView('tasks')} />;
      case 'tasks': return <TodoList tasks={tasks} setTasks={setTasks} onToggle={handleTaskToggle} />;
      case 'timer': return <Pomodoro onComplete={addMinutes} />;
      case 'stats': return <Statistics stats={stats} />;
      case 'ai': return <AISuggestions tasks={tasks} setTasks={setTasks} />;
      default: return <Hero onStart={() => setView('tasks')} />;
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-[#0b0c10]">
      <Navbar stats={stats} setView={setView} activeView={view} />
      <main className="flex-1 overflow-y-auto pt-16 pb-24 md:pb-8">
        {renderView()}
      </main>

      {/* Mobile Nav */}
      <div className="md:hidden fixed bottom-0 left-0 right-0 bg-[#1f2833] border-t-4 border-black p-2 flex justify-around items-center z-50">
        <button onClick={() => setView('home')} className={`p-2 ${view === 'home' ? 'text-yellow-400' : 'text-white'}`}>
          🏠
        </button>
        <button onClick={() => setView('tasks')} className={`p-2 ${view === 'tasks' ? 'text-yellow-400' : 'text-white'}`}>
          ⚔️
        </button>
        <button onClick={() => setView('timer')} className={`p-2 ${view === 'timer' ? 'text-yellow-400' : 'text-white'}`}>
          ⏳
        </button>
        <button onClick={() => setView('ai')} className={`p-2 ${view === 'ai' ? 'text-yellow-400' : 'text-white'}`}>
          🔮
        </button>
        <button onClick={() => setView('stats')} className={`p-2 ${view === 'stats' ? 'text-yellow-400' : 'text-white'}`}>
          📈
        </button>
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import { UserStats, View } from '../types';

