import React, { useState } from 'react';
import { Task } from '../types';

interface TodoListProps {
  tasks: Task[];
  setTasks: React.Dispatch<React.SetStateAction<Task[]>>;
  onToggle: (id: string) => void;
}

export const TodoList: React.FC<TodoListProps> = ({ tasks, setTasks, onToggle }) => {
  const [inputValue, setInputValue] = useState('');

  const addTask = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputValue.trim()) return;

    const newTask: Task = {
      id: Date.now().toString(),
      text: inputValue.trim(),
      completed: false,
      xp: 25 + Math.floor(Math.random() * 25)
    };

    setTasks([newTask, ...tasks]);
    setInputValue('');
  };

  const deleteTask = (id: string) => {
    setTasks(prev => prev.filter(t => t.id !== id));
  };

  return (
    <div className="max-w-2xl mx-auto p-4 md:p-8 space-y-8">
      <div className="text-center space-y-4">
        <h2 className="pixel-font text-2xl text-yellow-400">ACTIVE QUESTS</h2>
        <p className="retro-font text-xl text-gray-400">Defeat tasks to gain XP and gold!</p>
      </div>

      <form onSubmit={addTask} className="flex gap-2">
        <input 
          type="text" 
          value={inputValue}
          onChange={(e) => setInputValue(e.target.value)}
          placeholder="Enter a new quest..."
          className="flex-1 bg-[#1f2833] border-4 border-black p-4 pixel-font text-xs text-white focus:outline-none focus:border-yellow-400"
        />
        <button 
          type="submit"
          className="pixel-button pixel-font text-xs bg-green-500"
        >
          Add
        </button>
      </form>

      <div className="space-y-4">
        {tasks.length === 0 ? (
          <div className="p-12 text-center bg-[#1f2833] pixel-border border-4 border-dashed border-gray-600">
            <p className="pixel-font text-xs text-gray-500">NO QUESTS LOGGED. <br/><br/> RESTING AT THE TAVERN...</p>
          </div>
        ) : (
          tasks.map(task => (
            <div 
              key={task.id} 
              className={`flex items-center gap-4 p-4 bg-[#1f2833] pixel-border transition-all ${task.completed ? 'opacity-50' : 'hover:border-yellow-400'}`}
            >
              <button 
                onClick={() => onToggle(task.id)}
                className={`w-8 h-8 flex items-center justify-center border-4 border-black ${task.completed ? 'bg-green-500' : 'bg-[#0b0c10]'}`}
              >
                {task.completed && '✔️'}
              </button>

              <div className="flex-1">
                <p className={`pixel-font text-xs ${task.completed ? 'line-through text-gray-500' : 'text-white'}`}>
                  {task.text}
                </p>
                <div className="flex gap-2 mt-2">
                  <span className="text-[10px] pixel-font text-blue-400">+{task.xp} XP</span>
                  <span className="text-[10px] pixel-font text-yellow-400">+10 GOLD</span>
                </div>
              </div>

              <button 
                onClick={() => deleteTask(task.id)}
                className="text-red-500 hover:text-red-400 pixel-font text-xs"
              >
                🗑️
              </button>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';

interface PomodoroProps {
  onComplete: (minutes: number) => void;
}

type Mode = 'work' | 'break';

export const Pomodoro: React.FC<PomodoroProps> = ({ onComplete }) => {
  const [mode, setMode] = useState<Mode>('work');
  const [timeLeft, setTimeLeft] = useState(25 * 60);
  const [isActive, setIsActive] = useState(false);
  const timerRef = useRef<NodeJS.Timeout | null>(null);

  useEffect(() => {
    if (isActive && timeLeft > 0) {
      timerRef.current = setInterval(() => {
        setTimeLeft(prev => prev - 1);
      }, 1000);
    } else if (timeLeft === 0) {
      handleTimerComplete();
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
    }
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [isActive, timeLeft]);

  const handleTimerComplete = () => {
    setIsActive(false);
    if (mode === 'work') {
      onComplete(25);
      alert("Quest Session Complete! Time for a short rest.");
      setMode('break');
      setTimeLeft(5 * 60);
    } else {
      alert("Rest finished. Back to the adventure!");
      setMode('work');
      setTimeLeft(25 * 60);
    }
  };

  const toggleTimer = () => setIsActive(!isActive);

  const resetTimer = () => {
    setIsActive(false);
    setTimeLeft(mode === 'work' ? 25 * 60 : 5 * 60);
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="max-w-xl mx-auto p-4 md:p-12 text-center">
      <div className={`p-8 md:p-16 rounded-lg pixel-border transition-colors duration-500 ${mode === 'work' ? 'bg-[#1f2833]' : 'bg-[#2b4b3b]'}`}>
        <h2 className="pixel-font text-xl md:text-2xl mb-8 text-white uppercase tracking-widest">
          {mode === 'work' ? '⚔️ STUDY MODE' : '🧘 REST MODE'}
        </h2>

        <div className="pixel-font text-6xl md:text-8xl mb-12 text-yellow-400 font-bold tabular-nums drop-shadow-lg">
          {formatTime(timeLeft)}
        </div>

        <div className="flex flex-col md:flex-row gap-4 justify-center items-center">
          <button 
            onClick={toggleTimer}
            className={`pixel-button w-full md:w-48 ${isActive ? 'bg-orange-500' : 'bg-green-500'}`}
          >
            {isActive ? 'PAUSE' : 'START'}
          </button>
          <button 
            onClick={resetTimer}
            className="pixel-button w-full md:w-48 bg-gray-500"
          >
            RESET
          </button>
        </div>
      </div>

      <div className="mt-8 p-4 bg-[#0b0c10] pixel-border border-4 border-dashed border-gray-700">
        <p className="pixel-font text-[10px] text-gray-400 uppercase">
          Pro Tip: A 25-minute focus burst earns you 125 XP and 5 Gold!
        </p>
      </div>
    </div>
  );
};

import React from 'react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { UserStats } from '../types';

interface StatisticsProps {
  stats: UserStats;
}

export const Statistics: React.FC<StatisticsProps> = ({ stats }) => {
  // Dummy data for visualization
  const data = [
    { name: 'Mon', mins: Math.floor(stats.totalMinutes * 0.1) },
    { name: 'Tue', mins: Math.floor(stats.totalMinutes * 0.15) },
    { name: 'Wed', mins: Math.floor(stats.totalMinutes * 0.2) },
    { name: 'Thu', mins: Math.floor(stats.totalMinutes * 0.12) },
    { name: 'Fri', mins: Math.floor(stats.totalMinutes * 0.18) },
    { name: 'Sat', mins: Math.floor(stats.totalMinutes * 0.15) },
    { name: 'Sun', mins: Math.floor(stats.totalMinutes * 0.1) },
  ];

  const totalHours = (stats.totalMinutes / 60).toFixed(1);

  return (
    <div className="max-w-4xl mx-auto p-4 md:p-8 space-y-8">
      <h2 className="pixel-font text-2xl text-center text-blue-400">ADVENTURE LOG</h2>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <StatCard title="Total Focus" value={`${totalHours}h`} sub="Time Spent" color="text-yellow-400" />
        <StatCard title="Rank" value={`Lvl ${stats.level}`} sub="Student Adventurer" color="text-blue-400" />
        <StatCard title="Gold Earnt" value={stats.gold.toString()} sub="Currency" color="text-green-400" />
      </div>

      <div className="bg-[#1f2833] p-6 pixel-border h-[400px]">
        <h3 className="pixel-font text-sm mb-8 text-center text-gray-400">Weekly Focus Distribution</h3>
        <ResponsiveContainer width="100%" height="80%">
          <BarChart data={data}>
            <XAxis 
              dataKey="name" 
              stroke="#666" 
              tick={{ fontFamily: 'VT323', fontSize: 18 }} 
            />
            <YAxis 
              stroke="#666" 
              tick={{ fontFamily: 'VT323', fontSize: 18 }} 
            />
            <Tooltip 
              contentStyle={{ backgroundColor: '#0b0c10', border: '2px solid black', fontFamily: 'VT323' }}
            />
            <Bar dataKey="mins" fill="#facc15">
              {data.map((entry, index) => (
                <Cell key={`cell-${index}`} fill={index % 2 === 0 ? '#facc15' : '#ca8a04'} />
              ))}
            </Bar>
          </BarChart>
        </ResponsiveContainer>
      </div>

      <div className="bg-[#1f2833] p-4 pixel-border">
        <h3 className="pixel-font text-xs text-yellow-400 mb-2">Achievement Unlocked?</h3>
        <div className="flex gap-4">
           <div className="w-12 h-12 bg-gray-800 flex items-center justify-center grayscale">🔥</div>
           <div className="w-12 h-12 bg-gray-800 flex items-center justify-center grayscale">📖</div>
           <div className="w-12 h-12 bg-gray-800 flex items-center justify-center grayscale">👑</div>
           <div className="w-12 h-12 bg-gray-800 flex items-center justify-center grayscale">🗡️</div>
        </div>
        <p className="retro-font text-gray-500 mt-2">Study more to unlock these badges!</p>
      </div>
    </div>
  );
};

const StatCard: React.FC<{ title: string; value: string; sub: string; color: string }> = ({ title, value, sub, color }) => (
  <div className="bg-[#1f2833] p-6 pixel-border text-center">
    <p className="pixel-font text-[10px] text-gray-500 mb-2">{title}</p>
    <p className={`pixel-font text-2xl ${color} mb-1`}>{value}</p>
    <p className="retro-font text-lg text-gray-400">{sub}</p>
  </div>
);

import React, { useState } from 'react';
import { GoogleGenAI, Type } from '@google/genai';
import { Task } from '../types';

interface AISuggestionsProps {
  tasks: Task[];
  setTasks: React.Dispatch<React.SetStateAction<Task[]>>;
}

export const AISuggestions: React.FC<AISuggestionsProps> = ({ tasks, setTasks }) => {
  const [prompt, setPrompt] = useState('');
  const [loading, setLoading] = useState(false);
  const [suggestion, setSuggestion] = useState<string | null>(null);

  const getHelp = async () => {
    if (!prompt.trim()) return;
    setLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `I am a student on a "Study Quest". I need help breaking down this topic into 3 actionable "quests" (tasks): ${prompt}`,
        config: {
          systemInstruction: "You are a wise fantasy wizard mentor. Help the student break down their study goals into small, actionable tasks. Keep your language thematic (use words like quest, scrolls, mana, adventure).",
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              advice: { type: Type.STRING, description: "Mentor advice" },
              quests: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    title: { type: Type.STRING },
                    difficulty_xp: { type: Type.NUMBER }
                  },
                  required: ["title", "difficulty_xp"]
                }
              }
            },
            required: ["advice", "quests"]
          }
        }
      });

      const data = JSON.parse(response.text);
      setSuggestion(data.advice);

      // Option to add these as actual tasks
      if (data.quests) {
        const newTasks: Task[] = data.quests.map((q: any) => ({
          id: `ai-${Date.now()}-${Math.random()}`,
          text: q.title,
          completed: false,
          xp: q.difficulty_xp || 50
        }));
        setTasks(prev => [...newTasks, ...prev]);
      }
    } catch (err) {
      console.error(err);
      setSuggestion("The crystal ball is cloudy. Please try again later, brave adventurer.");
    } finally {
      setLoading(false);
      setPrompt('');
    }
  };

  return (
    <div className="max-w-2xl mx-auto p-4 md:p-8 space-y-8">
      <div className="text-center space-y-4">
        <h2 className="pixel-font text-2xl text-purple-400">THE SAGE'S CRYSTAL BALL</h2>
        <p className="retro-font text-xl text-gray-400">Ask for guidance on your learning journey.</p>
      </div>

      <div className="bg-[#1f2833] pixel-border p-6 flex flex-col gap-4">
        <textarea 
          value={prompt}
          onChange={(e) => setPrompt(e.target.value)}
          placeholder="I want to study Quantum Physics..."
          className="w-full h-32 bg-[#0b0c10] border-4 border-black p-4 pixel-font text-xs text-white focus:outline-none focus:border-purple-400 resize-none"
        />
        <button 
          onClick={getHelp}
          disabled={loading}
          className={`pixel-button pixel-font text-xs ${loading ? 'bg-gray-600 opacity-50 cursor-not-allowed' : 'bg-purple-600'}`}
        >
          {loading ? 'CONSULTING...' : 'SUMMON ADVICE'}
        </button>
      </div>

      {suggestion && (
        <div className="bg-[#2a1a3d] pixel-border p-6 animate-fade-in">
          <div className="flex items-center gap-4 mb-4">
             <div className="w-12 h-12 bg-purple-500 pixel-border flex items-center justify-center text-2xl">🧙‍♂️</div>
             <p className="pixel-font text-xs text-purple-200">The Sage speaks:</p>
          </div>
          <p className="retro-font text-xl text-white italic">
            "{suggestion}"
          </p>
          <p className="pixel-font text-[10px] text-green-400 mt-4">
             ✨ I have added 3 new quests to your log! ✨
          </p>
        </div>
      )}
    </div>
  );
};

