import React, { useState, useEffect, useRef } from 'react';

interface PomodoroProps {
  onComplete: (minutes: number) => void;
}

type Mode = 'work' | 'break';

export const Pomodoro: React.FC<PomodoroProps> = ({ onComplete }) => {
  const [mode, setMode] = useState<Mode>('work');
  const [timeLeft, setTimeLeft] = useState(25 * 60);
  const [isActive, setIsActive] = useState(false);
  // Fix: Use ReturnType<typeof setInterval> instead of NodeJS.Timeout for browser compatibility
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);

  useEffect(() => {
    if (isActive && timeLeft > 0) {
      timerRef.current = setInterval(() => {
        setTimeLeft(prev => prev - 1);
      }, 1000);
    } else if (timeLeft === 0) {
      handleTimerComplete();
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
    }
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [isActive, timeLeft]);

  const handleTimerComplete = () => {
    setIsActive(false);
    if (mode === 'work') {
      onComplete(25);
      alert("Quest Session Complete! Time for a short rest.");
      setMode('break');
      setTimeLeft(5 * 60);
    } else {
      alert("Rest finished. Back to the adventure!");
      setMode('work');
      setTimeLeft(25 * 60);
    }
  };

  const toggleTimer = () => setIsActive(!isActive);

  const resetTimer = () => {
    setIsActive(false);
    setTimeLeft(mode === 'work' ? 25 * 60 : 5 * 60);
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="max-w-xl mx-auto p-4 md:p-12 text-center">
      <div className={`p-8 md:p-16 rounded-lg pixel-border transition-colors duration-500 ${mode === 'work' ? 'bg-[#1f2833]' : 'bg-[#2b4b3b]'}`}>
        <h2 className="pixel-font text-xl md:text-2xl mb-8 text-white uppercase tracking-widest">
          {mode === 'work' ? '⚔️ STUDY MODE' : '🧘 REST MODE'}
        </h2>

        <div className="pixel-font text-6xl md:text-8xl mb-12 text-yellow-400 font-bold tabular-nums drop-shadow-lg">
          {formatTime(timeLeft)}
        </div>

        <div className="flex flex-col md:flex-row gap-4 justify-center items-center">
          <button 
            onClick={toggleTimer}
            className={`pixel-button w-full md:w-48 ${isActive ? 'bg-orange-500' : 'bg-green-500'}`}
          >
            {isActive ? 'PAUSE' : 'START'}
          </button>
          <button 
            onClick={resetTimer}
            className="pixel-button w-full md:w-48 bg-gray-500"
          >
            RESET
          </button>
        </div>
      </div>

      <div className="mt-8 p-4 bg-[#0b0c10] pixel-border border-4 border-dashed border-gray-700">
        <p className="pixel-font text-[10px] text-gray-400 uppercase">
          Pro Tip: A 25-minute focus burst earns you 125 XP and 5 Gold!
        </p>
      </div>
    </div>
  );
};

export interface Task {
  id: string;
  text: string;
  completed: boolean;
  xp: number;
  isPartyQuest?: boolean;
}

export interface PartyMember {
  id: string;
  name: string;
  level: number;
  status: 'online' | 'studying' | 'offline';
  avatar: string;
}

export interface Party {
  name: string;
  id: string;
  members: PartyMember[];
  guildXp: number;
  guildLevel: number;
}

export interface UserStats {
  level: number;
  xp: number;
  totalMinutes: number;
  gold: number;
}

export type View = 'home' | 'tasks' | 'timer' | 'stats' | 'ai' | 'party';

import React, { useState, useEffect } from 'react';
import { Hero } from './components/Hero';
import { Navbar } from './components/Navbar';
import { TodoList } from './components/TodoList';
import { Pomodoro } from './components/Pomodoro';
import { Statistics } from './components/Statistics';
import { AISuggestions } from './components/AISuggestions';
import { PartyView } from './components/PartyView';
import { Task, UserStats, View, Party } from './types';

const App: React.FC = () => {
  const [view, setView] = useState<View>('home');
  const [tasks, setTasks] = useState<Task[]>(() => {
    const saved = localStorage.getItem('quest_tasks');
    return saved ? JSON.parse(saved) : [];
  });

  const [stats, setStats] = useState<UserStats>(() => {
    const saved = localStorage.getItem('quest_stats');
    return saved ? JSON.parse(saved) : { level: 1, xp: 0, totalMinutes: 0, gold: 50 };
  });

  const [party, setParty] = useState<Party | null>(() => {
    const saved = localStorage.getItem('quest_party');
    return saved ? JSON.parse(saved) : null;
  });

  useEffect(() => {
    localStorage.setItem('quest_tasks', JSON.stringify(tasks));
  }, [tasks]);

  useEffect(() => {
    localStorage.setItem('quest_stats', JSON.stringify(stats));
  }, [stats]);

  useEffect(() => {
    localStorage.setItem('quest_party', JSON.stringify(party));
  }, [party]);

  const addMinutes = (minutes: number) => {
    setStats(prev => {
      const newMinutes = prev.totalMinutes + minutes;
      const bonus = party ? 1.2 : 1.0; // 20% Team Bonus
      const gainedXP = Math.floor(minutes * 5 * bonus);
      const newXP = prev.xp + gainedXP;
      const newLevel = Math.floor(newXP / 1000) + 1;

      if (party) {
        setParty(p => p ? { ...p, guildXp: p.guildXp + (minutes * 2) } : null);
      }

      return {
        ...prev,
        totalMinutes: newMinutes,
        xp: newXP,
        level: newLevel,
        gold: prev.gold + Math.floor(minutes / 5)
      };
    });
  };

  const handleTaskToggle = (id: string) => {
    setTasks(prev => prev.map(t => {
      if (t.id === id) {
        if (!t.completed) {
          const bonus = t.isPartyQuest ? 1.5 : 1.0;
          setStats(s => ({ ...s, xp: s.xp + Math.floor(t.xp * bonus), gold: s.gold + 10 }));
          if (t.isPartyQuest && party) {
            setParty(p => p ? { ...p, guildXp: p.guildXp + 50 } : null);
          }
        }
        return { ...t, completed: !t.completed };
      }
      return t;
    }));
  };

  const renderView = () => {
    switch (view) {
      case 'home': return <Hero onStart={() => setView('tasks')} />;
      case 'tasks': return <TodoList tasks={tasks} setTasks={setTasks} onToggle={handleTaskToggle} isPartyActive={!!party} />;
      case 'timer': return <Pomodoro onComplete={addMinutes} party={party} />;
      case 'stats': return <Statistics stats={stats} />;
      case 'ai': return <AISuggestions tasks={tasks} setTasks={setTasks} isPartyActive={!!party} />;
      case 'party': return <PartyView party={party} setParty={setParty} />;
      default: return <Hero onStart={() => setView('tasks')} />;
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-[#0b0c10]">
      <Navbar stats={stats} setView={setView} activeView={view} />
      <main className="flex-1 overflow-y-auto pt-16 pb-24 md:pb-8">
        {renderView()}
      </main>

      {/* Mobile Nav */}
      <div className="md:hidden fixed bottom-0 left-0 right-0 bg-[#1f2833] border-t-4 border-black p-2 flex justify-around items-center z-50">
        <button onClick={() => setView('home')} className={`p-2 ${view === 'home' ? 'text-yellow-400' : 'text-white'}`}>🏠</button>
        <button onClick={() => setView('tasks')} className={`p-2 ${view === 'tasks' ? 'text-yellow-400' : 'text-white'}`}>⚔️</button>
        <button onClick={() => setView('party')} className={`p-2 ${view === 'party' ? 'text-yellow-400' : 'text-white'}`}>🛡️</button>
        <button onClick={() => setView('timer')} className={`p-2 ${view === 'timer' ? 'text-yellow-400' : 'text-white'}`}>⏳</button>
        <button onClick={() => setView('ai')} className={`p-2 ${view === 'ai' ? 'text-yellow-400' : 'text-white'}`}>🔮</button>
        <button onClick={() => setView('stats')} className={`p-2 ${view === 'stats' ? 'text-yellow-400' : 'text-white'}`}>📈</button>
      </div>
    </div>
  );
};

export default App;

