              >
                🗑️
              </button>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Party } from '../types';

interface PomodoroProps {
  onComplete: (minutes: number) => void;
  party: Party | null;
}

type Mode = 'work' | 'break';

export const Pomodoro: React.FC<PomodoroProps> = ({ onComplete, party }) => {
  const [mode, setMode] = useState<Mode>('work');
  const [timeLeft, setTimeLeft] = useState(25 * 60);
  const [isActive, setIsActive] = useState(false);
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);

  useEffect(() => {
    if (isActive && timeLeft > 0) {
      timerRef.current = setInterval(() => {
        setTimeLeft(prev => prev - 1);
      }, 1000);
    } else if (timeLeft === 0) {
      handleTimerComplete();
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
    }
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [isActive, timeLeft]);

  const handleTimerComplete = () => {
    setIsActive(false);
    if (mode === 'work') {
      onComplete(25);
      alert("Quest Session Complete! Time for a short rest.");
      setMode('break');
      setTimeLeft(5 * 60);
    } else {
      alert("Rest finished. Back to the adventure!");
      setMode('work');
      setTimeLeft(25 * 60);
    }
  };

  const toggleTimer = () => setIsActive(!isActive);

  const resetTimer = () => {
    setIsActive(false);
    setTimeLeft(mode === 'work' ? 25 * 60 : 5 * 60);
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="max-w-xl mx-auto p-4 md:p-12 text-center">
      <div className={`p-8 md:p-16 rounded-lg pixel-border transition-colors duration-500 ${mode === 'work' ? 'bg-[#1f2833]' : 'bg-[#2b4b3b]'}`}>
        <h2 className="pixel-font text-xl md:text-2xl mb-8 text-white uppercase tracking-widest">
          {mode === 'work' ? (party ? '🛡️ GUILD CO-OP' : '⚔️ STUDY MODE') : '🧘 REST MODE'}
        </h2>

        <div className="pixel-font text-6xl md:text-8xl mb-12 text-yellow-400 font-bold tabular-nums drop-shadow-lg">
          {formatTime(timeLeft)}
        </div>

        {isActive && party && mode === 'work' && (
          <div className="flex justify-center gap-4 mb-8">
            {party.members.map(m => (
              <div key={m.id} className="relative group">
                <div className="text-2xl animate-bounce" style={{ animationDelay: `${Math.random()}s` }}>
                  {m.avatar}
                </div>
                <div className="absolute -bottom-6 left-1/2 -translate-x-1/2 text-[8px] pixel-font text-white opacity-0 group-hover:opacity-100 transition-opacity">
                  {m.name.split(' ')[0]}
                </div>
              </div>
            ))}
          </div>
        )}

        <div className="flex flex-col md:flex-row gap-4 justify-center items-center">
          <button 
            onClick={toggleTimer}
            className={`pixel-button w-full md:w-48 ${isActive ? 'bg-orange-500' : 'bg-green-500'}`}
          >
            {isActive ? 'PAUSE' : 'START'}
          </button>
          <button 
            onClick={resetTimer}
            className="pixel-button w-full md:w-48 bg-gray-500"
          >
            RESET
          </button>
        </div>
      </div>

      <div className="mt-8 p-4 bg-[#0b0c10] pixel-border border-4 border-dashed border-gray-700">
        <p className="pixel-font text-[10px] text-gray-400 uppercase">
          {party 
            ? "Team Synergy Active: +20% XP bonus for studying together!" 
            : "Pro Tip: A 25-minute focus burst earns you 125 XP and 5 Gold!"}
        </p>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { GoogleGenAI, Type } from '@google/genai';
import { Task } from '../types';

interface AISuggestionsProps {
  tasks: Task[];
  setTasks: React.Dispatch<React.SetStateAction<Task[]>>;
  isPartyActive?: boolean;
}

export const AISuggestions: React.FC<AISuggestionsProps> = ({ tasks, setTasks, isPartyActive }) => {
  const [prompt, setPrompt] = useState('');
  const [loading, setLoading] = useState(false);
  const [suggestion, setSuggestion] = useState<string | null>(null);

  const getHelp = async () => {
    if (!prompt.trim()) return;
    setLoading(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `I am a student on a "Study Quest". ${isPartyActive ? 'I am currently in a Guild.' : ''} I need help breaking down this topic into 3 actionable quests: ${prompt}`,
        config: {
          systemInstruction: `You are a wise fantasy wizard mentor. Help the student break down their study goals into small, actionable tasks. 
          Keep your language thematic (use words like quest, scrolls, mana, adventure). 
          ${isPartyActive ? 'Include one "World Boss" task which is extra difficult and meant for the whole guild.' : ''}`,
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              advice: { type: Type.STRING, description: "Mentor advice" },
              quests: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    title: { type: Type.STRING },
                    difficulty_xp: { type: Type.NUMBER },
                    isPartyQuest: { type: Type.BOOLEAN }
                  },
                  required: ["title", "difficulty_xp"]
                }
              }
            },
            required: ["advice", "quests"]
          }
        }
      });

      const data = JSON.parse(response.text);
      setSuggestion(data.advice);

      if (data.quests) {
        const newTasks: Task[] = data.quests.map((q: any) => ({
          id: `ai-${Date.now()}-${Math.random()}`,
          text: q.title,
          completed: false,
          xp: q.difficulty_xp || 50,
          isPartyQuest: q.isPartyQuest || false
        }));
        setTasks(prev => [...newTasks, ...prev]);
      }
    } catch (err) {
      console.error(err);
      setSuggestion("The crystal ball is cloudy. Please try again later, brave adventurer.");
    } finally {
      setLoading(false);
      setPrompt('');
    }
  };

  return (
    <div className="max-w-2xl mx-auto p-4 md:p-8 space-y-8">
      <div className="text-center space-y-4">
        <h2 className="pixel-font text-2xl text-purple-400">THE SAGE'S CRYSTAL BALL</h2>
        <p className="retro-font text-xl text-gray-400">Ask for guidance on your learning journey.</p>
      </div>

      <div className="bg-[#1f2833] pixel-border p-6 flex flex-col gap-4">
        <textarea 
          value={prompt}
          onChange={(e) => setPrompt(e.target.value)}
          placeholder="I want to study Quantum Physics..."
          className="w-full h-32 bg-[#0b0c10] border-4 border-black p-4 pixel-font text-xs text-white focus:outline-none focus:border-purple-400 resize-none"
        />
        <button 
          onClick={getHelp}
          disabled={loading}
          className={`pixel-button pixel-font text-xs ${loading ? 'bg-gray-600 opacity-50 cursor-not-allowed' : 'bg-purple-600'}`}
        >
          {loading ? 'CONSULTING...' : 'SUMMON ADVICE'}
        </button>
      </div>

      {suggestion && (
        <div className="bg-[#2a1a3d] pixel-border p-6 animate-fade-in">
          <div className="flex items-center gap-4 mb-4">
             <div className="w-12 h-12 bg-purple-500 pixel-border flex items-center justify-center text-2xl">🧙‍♂️</div>
             <p className="pixel-font text-xs text-purple-200">The Sage speaks:</p>
          </div>
          <p className="retro-font text-xl text-white italic">
            "{suggestion}"
          </p>
          <p className="pixel-font text-[10px] text-green-400 mt-4">
             ✨ I have added new quests to your log! ✨
          </p>
        </div>
      )}
    </div>
  );
};

