import React, { useState, useEffect, useCallback } from 'react';
import { Hero } from './components/Hero';
import { Navbar } from './components/Navbar';
import { TodoList } from './components/TodoList';
import { Pomodoro } from './components/Pomodoro';
import { Statistics } from './components/Statistics';
import { AISuggestions } from './components/AISuggestions';
import { PartyView } from './components/PartyView';
import { DailyBonusModal } from './components/DailyBonusModal';
import { Task, UserStats, View, Party } from './types';

const App: React.FC = () => {
  const [view, setView] = useState<View>('home');
  const [showBonus, setShowBonus] = useState(false);

  // Helper to ensure data structure is intact
  const validateStats = (data: any): UserStats => {
    const defaults: UserStats = {
      level: 1,
      xp: 0,
      totalMinutes: 0,
      gold: 50,
      timerSettings: { work: 25, break: 5 }
    };
    if (!data) return defaults;
    return {
      ...defaults,
      ...data,
      timerSettings: { ...defaults.timerSettings, ...(data.timerSettings || {}) }
    };
  };

  const [tasks, setTasks] = useState<Task[]>(() => {
    try {
      const saved = localStorage.getItem('quest_tasks');
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      console.error("Failed to parse tasks, resetting to empty.");
      return [];
    }
  });

  const [stats, setStats] = useState<UserStats>(() => {
    try {
      const saved = localStorage.getItem('quest_stats');
      return validateStats(saved ? JSON.parse(saved) : null);
    } catch (e) {
      console.error("Failed to parse stats, resetting to defaults.");
      return validateStats(null);
    }
  });

  const [party, setParty] = useState<Party | null>(() => {
    try {
      const saved = localStorage.getItem('quest_party');
      return saved ? JSON.parse(saved) : null;
    } catch (e) {
      return null;
    }
  });

  useEffect(() => {
    localStorage.setItem('quest_tasks', JSON.stringify(tasks));
  }, [tasks]);

  useEffect(() => {
    localStorage.setItem('quest_stats', JSON.stringify(stats));
  }, [stats]);

  useEffect(() => {
    localStorage.setItem('quest_party', JSON.stringify(party));
  }, [party]);

  useEffect(() => {
    const today = new Date().toDateString();
    if (stats.lastLogin !== today) {
      setShowBonus(true);
    }
  }, []);

  const claimBonus = () => {
    const today = new Date().toDateString();
    setStats(prev => ({
      ...prev,
      gold: prev.gold + 100,
      xp: prev.xp + 200,
      lastLogin: today
    }));
    setShowBonus(false);
  };

  const addMinutes = (minutes: number) => {
    setStats(prev => {
      const newMinutes = prev.totalMinutes + minutes;
      const bonus = party ? 1.2 : 1.0; 
      const gainedXP = Math.floor(minutes * 5 * bonus);
      const newXP = prev.xp + gainedXP;
      const newLevel = Math.floor(newXP / 1000) + 1;

      if (party) {
        setParty(p => p ? { ...p, guildXp: p.guildXp + (minutes * 2) } : null);
      }

      return {
        ...prev,
        totalMinutes: newMinutes,
        xp: newXP,
        level: newLevel,
        gold: prev.gold + Math.floor(minutes / 5)
      };
    });
  };

  const updateTimerSettings = (work: number, rest: number) => {
    setStats(prev => ({
      ...prev,
      timerSettings: { work, break: rest }
    }));
  };

  const handleTaskToggle = (id: string) => {
    setTasks(prev => prev.map(t => {
      if (t.id === id) {
        if (!t.completed) {
          const bonus = t.isPartyQuest ? 1.5 : 1.0;
          setStats(s => ({ ...s, xp: s.xp + Math.floor(t.xp * bonus), gold: s.gold + 10 }));
          if (t.isPartyQuest && party) {
            setParty(p => p ? { ...p, guildXp: p.guildXp + 50 } : null);
          }
        }
        return { ...t, completed: !t.completed };
      }
      return t;
    }));
  };

  const handleMaintenance = useCallback((action: 'repair' | 'reset' | 'import', data?: any) => {
    if (action === 'repair') {
      setStats(prev => validateStats(prev));
      alert("Chronicles repaired! Missing data fields have been restored to defaults.");
    } else if (action === 'reset') {
      if (confirm("WARNING: This will erase all progress. Are you sure?")) {
        localStorage.clear();
        window.location.reload();
      }
    } else if (action === 'import' && data) {
      try {
        const parsed = JSON.parse(data);
        if (parsed.stats) setStats(validateStats(parsed.stats));
        if (parsed.tasks) setTasks(parsed.tasks);
        if (parsed.party) setParty(parsed.party);
        alert("Import successful! Your adventure has been restored.");
      } catch (e) {
        alert("Corrupted Scroll! Could not import data.");
      }
    }
  }, []);

  const renderView = () => {
    switch (view) {
      case 'home': return <Hero onStart={() => setView('tasks')} />;
      case 'tasks': return <TodoList tasks={tasks} setTasks={setTasks} onToggle={handleTaskToggle} isPartyActive={!!party} />;
      case 'timer': return (
        <Pomodoro 
          onComplete={addMinutes} 
          party={party} 
          settings={stats.timerSettings} 
          onUpdateSettings={updateTimerSettings}
        />
      );
      case 'stats': return (
        <Statistics 
          stats={stats} 
          tasks={tasks} 
          party={party} 
          onMaintenance={handleMaintenance} 
        />
      );
      case 'ai': return <AISuggestions tasks={tasks} setTasks={setTasks} isPartyActive={!!party} />;
      case 'party': return <PartyView party={party} setParty={setParty} />;
      default: return <Hero onStart={() => setView('tasks')} />;
    }
  };

  return (
    <div className="min-h-screen flex flex-col bg-[#0b0c10]">
      <Navbar stats={stats} setView={setView} activeView={view} />
      <main className="flex-1 overflow-y-auto pt-16 pb-24 md:pb-8">
        {renderView()}
      </main>

      {showBonus && <DailyBonusModal onClaim={claimBonus} />}

      {/* Mobile Nav */}
      <div className="md:hidden fixed bottom-0 left-0 right-0 bg-[#1f2833] border-t-4 border-black p-2 flex justify-around items-center z-50">
        <button onClick={() => setView('home')} className={`p-2 ${view === 'home' ? 'text-yellow-400' : 'text-white'}`}>🏠</button>
        <button onClick={() => setView('tasks')} className={`p-2 ${view === 'tasks' ? 'text-yellow-400' : 'text-white'}`}>⚔️</button>
        <button onClick={() => setView('party')} className={`p-2 ${view === 'party' ? 'text-yellow-400' : 'text-white'}`}>🛡️</button>
        <button onClick={() => setView('timer')} className={`p-2 ${view === 'timer' ? 'text-yellow-400' : 'text-white'}`}>⏳</button>
        <button onClick={() => setView('ai')} className={`p-2 ${view === 'ai' ? 'text-yellow-400' : 'text-white'}`}>🔮</button>
        <button onClick={() => setView('stats')} className={`p-2 ${view === 'stats' ? 'text-yellow-400' : 'text-white'}`}>📈</button>
      </div>
    </div>
  );
};

export default App;

import React, { useRef } from 'react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { UserStats, Task, Party } from '../types';

interface StatisticsProps {
  stats: UserStats;
  tasks: Task[];
  party: Party | null;
  onMaintenance: (action: 'repair' | 'reset' | 'import', data?: any) => void;
}

export const Statistics: React.FC<StatisticsProps> = ({ stats, tasks, party, onMaintenance }) => {
  const fileInputRef = useRef<HTMLInputElement>(null);

  const data = [
    { name: 'Mon', mins: Math.floor(stats.totalMinutes * 0.1) },
    { name: 'Tue', mins: Math.floor(stats.totalMinutes * 0.15) },
    { name: 'Wed', mins: Math.floor(stats.totalMinutes * 0.2) },
    { name: 'Thu', mins: Math.floor(stats.totalMinutes * 0.12) },
    { name: 'Fri', mins: Math.floor(stats.totalMinutes * 0.18) },
    { name: 'Sat', mins: Math.floor(stats.totalMinutes * 0.15) },
    { name: 'Sun', mins: Math.floor(stats.totalMinutes * 0.1) },
  ];

  const totalHours = (stats.totalMinutes / 60).toFixed(1);

  const exportSave = () => {
    const saveData = JSON.stringify({ stats, tasks, party });
    const blob = new Blob([saveData], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `study_quest_save_${new Date().toISOString().split('T')[0]}.json`;
    link.click();
  };

  const importSave = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        onMaintenance('import', ev.target?.result);
      };
      reader.readAsText(file);
    }
  };

  return (
    <div className="max-w-4xl mx-auto p-4 md:p-8 space-y-8 pb-32">
      <h2 className="pixel-font text-2xl text-center text-blue-400">ADVENTURE LOG</h2>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <StatCard title="Total Focus" value={`${totalHours}h`} sub="Time Spent" color="text-yellow-400" />
        <StatCard title="Rank" value={`Lvl ${stats.level}`} sub="Student Adventurer" color="text-blue-400" />
        <StatCard title="Gold Earnt" value={stats.gold.toString()} sub="Currency" color="text-green-400" />
      </div>

      <div className="bg-[#1f2833] p-6 pixel-border h-[400px]">
        <h3 className="pixel-font text-sm mb-8 text-center text-gray-400 uppercase tracking-widest">Weekly Focus Distribution</h3>
        <ResponsiveContainer width="100%" height="80%">
          <BarChart data={data}>
            <XAxis dataKey="name" stroke="#666" tick={{ fontFamily: 'VT323', fontSize: 18 }} />
            <YAxis stroke="#666" tick={{ fontFamily: 'VT323', fontSize: 18 }} />
            <Tooltip contentStyle={{ backgroundColor: '#0b0c10', border: '2px solid black', fontFamily: 'VT323' }} />
            <Bar dataKey="mins" fill="#facc15">
              {data.map((entry, index) => (
                <Cell key={`cell-${index}`} fill={index % 2 === 0 ? '#facc15' : '#ca8a04'} />
              ))}
            </Bar>
          </BarChart>
        </ResponsiveContainer>
      </div>

      {/* Maintenance Hub */}
      <div className="bg-[#1f2833] p-6 pixel-border border-orange-900/50">
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center gap-3">
             <span className="text-2xl">🔧</span>
             <div>
               <h3 className="pixel-font text-xs text-orange-400">MAINTENANCE HUB</h3>
               <p className="retro-font text-sm text-gray-500 uppercase">System diagnostics and emergency repair</p>
             </div>
          </div>
          <div className="h-4 w-4 rounded-full bg-green-500 animate-pulse shadow-[0_0_10px_rgba(34,197,94,0.5)]"></div>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          <ToolButton 
            title="Auto-Fix" 
            desc="Repair broken save data" 
            onClick={() => onMaintenance('repair')} 
            color="bg-blue-600"
          />
          <ToolButton 
            title="Export Scroll" 
            desc="Download progress" 
            onClick={exportSave} 
            color="bg-purple-600"
          />
          <ToolButton 
            title="Import Scroll" 
            desc="Upload save file" 
            onClick={() => fileInputRef.current?.click()} 
            color="bg-green-600"
          />
          <ToolButton 
            title="Factory Reset" 
            desc="Wipe all chronicles" 
            onClick={() => onMaintenance('reset')} 
            color="bg-red-600"
          />
        </div>
        <input 
          type="file" 
          ref={fileInputRef} 
          onChange={importSave} 
          accept=".json" 
          className="hidden" 
        />
      </div>

      <div className="bg-[#1f2833] p-4 pixel-border">
        <h3 className="pixel-font text-xs text-yellow-400 mb-2 uppercase">Achievements</h3>
        <div className="flex gap-4">
           <Badge icon="🔥" active={stats.totalMinutes > 60} label="Burnt Midnight" />
           <Badge icon="📖" active={tasks.filter(t => t.completed).length >= 5} label="Scholar" />
           <Badge icon="👑" active={stats.level >= 10} label="Master" />
           <Badge icon="🛡️" active={!!party} label="Guildmate" />
        </div>
        <p className="retro-font text-gray-500 mt-4 uppercase">Continue your quest to unlock legendary titles!</p>
      </div>
    </div>
  );
};

