import React, { useState, useEffect, useRef } from 'react';
import { Party } from '../types';

interface PomodoroProps {
  onComplete: (minutes: number) => void;
  party: Party | null;
  settings: { work: number; break: number };
  onUpdateSettings: (work: number, rest: number) => void;
  deepFocus: boolean;
  setDeepFocus: (v: boolean) => void;
}

type Mode = 'work' | 'break';

export const Pomodoro: React.FC<PomodoroProps> = ({ onComplete, party, settings, onUpdateSettings, deepFocus, setDeepFocus }) => {
  const [mode, setMode] = useState<Mode>('work');
  const [timeLeft, setTimeLeft] = useState(settings.work * 60);
  const [isActive, setIsActive] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);

  useEffect(() => {
    if (!isActive) {
      setTimeLeft(mode === 'work' ? settings.work * 60 : settings.break * 60);
    }
  }, [settings, mode, isActive]);

  useEffect(() => {
    if (isActive && timeLeft > 0) {
      timerRef.current = setInterval(() => {
        setTimeLeft(prev => prev - 1);
      }, 1000);
    } else if (timeLeft === 0) {
      handleTimerComplete();
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
    }
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [isActive, timeLeft]);

  const handleTimerComplete = () => {
    setIsActive(false);
    if (mode === 'work') {
      onComplete(settings.work);
      setMode('break');
      setTimeLeft(settings.break * 60);
    } else {
      setMode('work');
      setTimeLeft(settings.work * 60);
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
  };

  if (deepFocus) {
    return (
      <div className="fixed inset-0 bg-black flex flex-col items-center justify-center z-[100] animate-fade-in">
        <div className="text-center space-y-12">
          <h2 className="pixel-font text-xl text-gray-500 tracking-[1em] uppercase">Deep Focus</h2>
          <div className="text-[12rem] md:text-[20rem] font-bold text-white tabular-nums drop-shadow-[0_0_20px_rgba(255,255,255,0.2)]">
            {formatTime(timeLeft)}
          </div>
          <div className="flex gap-12 justify-center">
            <button onClick={() => setIsActive(!isActive)} className="text-white pixel-font text-2xl hover:text-yellow-400">
              {isActive ? 'PAUSE' : 'RESUME'}
            </button>
            <button onClick={() => setDeepFocus(false)} className="text-gray-700 pixel-font text-sm hover:text-red-500">
              EXIT FOCUS
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto p-4 md:p-8 lg:p-12 flex flex-col items-center justify-center min-h-[calc(100vh-8rem)]">
      <div className={`w-full max-w-2xl p-8 md:p-16 lg:p-20 rounded-lg pixel-border transition-all duration-500 relative shadow-2xl ${mode === 'work' ? 'bg-[#1f2833]' : 'bg-[#2b4b3b]'}`}>

        <div className="absolute top-6 right-6 flex gap-2">
           <button onClick={() => setDeepFocus(true)} className="p-2 bg-black/20 rounded-full text-xl" title="Deep Focus Mode">👁️</button>
           <button onClick={() => setShowSettings(!showSettings)} className="p-2 bg-black/20 rounded-full text-xl">⚙️</button>
        </div>

        {showSettings && !isActive && (
          <div className="absolute inset-x-8 top-20 z-20 p-6 bg-[#0b0c10] pixel-border space-y-4 animate-fade-in shadow-2xl">
            <h3 className="pixel-font text-xs text-yellow-400 text-center uppercase">Settings</h3>
            <div className="grid grid-cols-2 gap-4">
              <input type="number" value={settings.work} onChange={(e) => onUpdateSettings(parseInt(e.target.value), settings.break)} className="bg-black p-2 pixel-font text-xs text-white" />
              <input type="number" value={settings.break} onChange={(e) => onUpdateSettings(settings.work, parseInt(e.target.value))} className="bg-black p-2 pixel-font text-xs text-white" />
            </div>
            <button onClick={() => setShowSettings(false)} className="pixel-button w-full">Apply</button>
          </div>
        )}

        <div className="text-center space-y-6">
          <h2 className="pixel-font text-xl md:text-3xl text-white uppercase tracking-[0.2em]">
            {mode === 'work' ? (party ? '🛡️ GUILD FOCUS' : '⚔️ SOLO QUEST') : '🧘 RECOVERY'}
          </h2>
          <div className="pixel-font text-7xl md:text-[10rem] text-yellow-400 py-8">
            {formatTime(timeLeft)}
          </div>
          <div className="flex flex-col md:flex-row gap-6 justify-center">
            <button onClick={() => setIsActive(!isActive)} className={`pixel-button py-4 px-12 text-lg ${isActive ? 'bg-orange-500' : 'bg-green-500'}`}>
              {isActive ? 'PAUSE' : 'START'}
            </button>
            <button onClick={() => { setIsActive(false); setTimeLeft(settings.work * 60); }} className="pixel-button py-4 px-12 text-lg bg-gray-500">
              RESET
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { GoogleGenAI, Type } from '@google/genai';
import { Task } from '../types';

interface AISuggestionsProps {
  tasks: Task[];
  setTasks: React.Dispatch<React.SetStateAction<Task[]>>;
  isPartyActive?: boolean;
  mana: number;
  onUseMana: (amt: number) => void;
}

export const AISuggestions: React.FC<AISuggestionsProps> = ({ tasks, setTasks, isPartyActive, mana, onUseMana }) => {
  const [prompt, setPrompt] = useState('');
  const [loading, setLoading] = useState(false);
  const [suggestion, setSuggestion] = useState<{advice: string; roadmap: string[]} | null>(null);

  const MANA_COST = 20;

  const getHelp = async () => {
    if (!prompt.trim() || mana < MANA_COST) return;
    setLoading(true);
    onUseMana(MANA_COST);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Topic: ${prompt}.`,
        config: {
          systemInstruction: `You are the Great Study Sage. Create a professional study guide. Return advice as a summary and roadmap as an array of steps. Also provide 3 tasks with title and difficulty_xp.`,
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              advice: { type: Type.STRING },
              roadmap: { type: Type.ARRAY, items: { type: Type.STRING } },
              quests: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: { title: { type: Type.STRING }, difficulty_xp: { type: Type.NUMBER } },
                  required: ["title", "difficulty_xp"]
                }
              }
            },
            required: ["advice", "roadmap", "quests"]
          }
        }
      });

      const data = JSON.parse(response.text);
      setSuggestion({ advice: data.advice, roadmap: data.roadmap });
      const newTasks: Task[] = data.quests.map((q: any) => ({
        id: `ai-${Date.now()}-${Math.random()}`,
        text: q.title,
        completed: false,
        xp: q.difficulty_xp || 50
      }));
      setTasks(prev => [...newTasks, ...prev]);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
      setPrompt('');
    }
  };

  return (
    <div className="max-w-2xl mx-auto p-4 md:p-8 space-y-8">
      <div className="text-center space-y-4">
        <h2 className="pixel-font text-2xl text-purple-400">THE GREAT LIBRARY</h2>
        <div className="flex justify-center items-center gap-2">
          <span className="text-purple-400 pixel-font text-[10px]">MANA: {mana}/100</span>
          <div className="w-32 h-2 bg-gray-900 border border-black">
            <div className="h-full bg-purple-500 transition-all" style={{ width: `${mana}%` }}></div>
          </div>
        </div>
      </div>

      <div className="bg-[#1f2833] pixel-border p-6 flex flex-col gap-4">
        <textarea 
          value={prompt}
          onChange={(e) => setPrompt(e.target.value)}
          placeholder="What do you want to learn today?"
          className="w-full h-24 bg-[#0b0c10] border-4 border-black p-4 pixel-font text-[10px] text-white focus:outline-none focus:border-purple-400 resize-none"
        />
        <button 
          onClick={getHelp}
          disabled={loading || mana < MANA_COST}
          className={`pixel-button pixel-font text-xs ${loading || mana < MANA_COST ? 'bg-gray-600 opacity-50' : 'bg-purple-600'}`}
        >
          {mana < MANA_COST ? 'INSUFFICIENT MANA' : loading ? 'SUMMONING...' : `EXPEND ${MANA_COST} MANA`}
        </button>
        <p className="retro-font text-xs text-gray-500 text-center uppercase italic">Mana regenerates slowly over time (1 MP / min)</p>
      </div>

      {suggestion && (
        <div className="bg-[#fefce8] text-black pixel-border p-6 animate-fade-in space-y-4">
          <h3 className="pixel-font text-sm uppercase">Sage's Wisdom</h3>
          <p className="retro-font text-xl italic">"{suggestion.advice}"</p>
          <div className="bg-black/5 p-4 space-y-2">
            {suggestion.roadmap.map((step, i) => (
              <p key={i} className="retro-font text-lg">{i+1}. {step}</p>
            ))}
          </div>
          <button onClick={() => setSuggestion(null)} className="pixel-font text-[8px] text-red-600">DISMISS</button>
        </div>
      )}
    </div>
  );
};

import React from 'react';
import { UserStats, Skin } from '../types';

interface ShopProps {
  stats: UserStats;
  setStats: React.Dispatch<React.SetStateAction<UserStats>>;
  onPurchase: (skin: Skin) => boolean;
}

const ALL_SKINS: Skin[] = [
  { id: 'char-knight', name: 'Elite Knight', type: 'character', cost: 1500, icon: '🛡️' },
  { id: 'char-mage', name: 'Archmage', type: 'character', cost: 2500, icon: '🧙' },
  { id: 'char-ninja', name: 'Shinobi', type: 'character', cost: 3000, icon: '🥷' },
  { id: 'bg-dungeon', name: 'Deep Dungeon', type: 'background', cost: 1000, icon: '🏰', styleClass: 'bg-[#1a1a1a]' },
  { id: 'bg-forest', name: 'Mystic Woods', type: 'background', cost: 2000, icon: '🌳', styleClass: 'bg-[#0f2d1a]' },
  { id: 'bg-cosmos', name: 'Deep Space', type: 'background', cost: 5000, icon: '🌌', styleClass: 'bg-[#050510]' },
];

export const Shop: React.FC<ShopProps> = ({ stats, setStats, onPurchase }) => {
  const selectSkin = (skin: Skin) => {
    if (skin.type === 'character') {
      setStats(prev => ({ ...prev, activeCharacter: skin.icon }));
    } else {
      setStats(prev => ({ ...prev, activeBackground: skin.styleClass || 'bg-[#0b0c10]' }));
    }
  };

  return (
    <div className="max-w-4xl mx-auto p-4 md:p-8 space-y-8 pb-32">
      <div className="text-center">
        <h2 className="pixel-font text-2xl text-yellow-400">VANITY VAULT</h2>
        <p className="retro-font text-xl text-gray-400">Exchange your hard-earned XP for legendary skins.</p>
        <div className="mt-4 inline-block bg-blue-900/40 p-2 pixel-border">
          <span className="pixel-font text-xs text-blue-300">TOTAL XP: {stats.xp}</span>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <section className="space-y-4">
          <h3 className="pixel-font text-sm text-white uppercase border-b border-gray-800 pb-2">Character Skins</h3>
          <div className="space-y-4">
            {ALL_SKINS.filter(s => s.type === 'character').map(skin => (
              <SkinCard 
                key={skin.id} 
                skin={skin} 
                isUnlocked={stats.unlockedSkins.includes(skin.id)}
                isActive={stats.activeCharacter === skin.icon}
                onBuy={() => onPurchase(skin)}
                onSelect={() => selectSkin(skin)}
              />
            ))}
          </div>
        </section>

        <section className="space-y-4">
          <h3 className="pixel-font text-sm text-white uppercase border-b border-gray-800 pb-2">Environment Themes</h3>
          <div className="space-y-4">
            {ALL_SKINS.filter(s => s.type === 'background').map(skin => (
              <SkinCard 
                key={skin.id} 
                skin={skin} 
                isUnlocked={stats.unlockedSkins.includes(skin.id)}
                isActive={stats.activeBackground === skin.styleClass}
                onBuy={() => onPurchase(skin)}
                onSelect={() => selectSkin(skin)}
              />
            ))}
          </div>
        </section>
      </div>
    </div>
  );
};

const SkinCard: React.FC<{ skin: Skin; isUnlocked: boolean; isActive: boolean; onBuy: () => void; onSelect: () => void }> = ({ skin, isUnlocked, isActive, onBuy, onSelect }) => (
  <div className={`bg-[#1f2833] pixel-border p-4 flex items-center justify-between transition-all ${isActive ? 'border-yellow-400 bg-[#252e39]' : ''}`}>
    <div className="flex items-center gap-4">
      <div className="w-12 h-12 bg-black flex items-center justify-center text-3xl pixel-border">
        {skin.icon}
      </div>
      <div>
        <p className="pixel-font text-[10px] text-white">{skin.name}</p>
        {!isUnlocked && <p className="retro-font text-sm text-yellow-400">{skin.cost} XP</p>}
        {isUnlocked && <p className="retro-font text-sm text-green-500 uppercase">Unlocked</p>}
      </div>
    </div>

    {isUnlocked ? (
      <button 
        onClick={onSelect}
        disabled={isActive}
        className={`pixel-font text-[8px] px-3 py-2 ${isActive ? 'bg-gray-700 text-gray-500' : 'bg-blue-600 hover:bg-blue-500'}`}
      >
        {isActive ? 'ACTIVE' : 'EQUIP'}
      </button>
    ) : (
      <button 
        onClick={onBuy}
        className="pixel-button bg-yellow-400 text-[8px] py-2"
      >
        BUY
      </button>
    )}
  </div>
);

