/**
 * Security utilities for the Study Quest application.
 * Focuses on input validation and sanitization to prevent XSS and malicious data injection.
 */

export const sanitizeText = (text: string): string => {
  const div = document.createElement('div');
  div.textContent = text;
  return div.innerHTML;
};

export const validateString = (
  input: string, 
  options: { min?: number; max?: number; pattern?: RegExp } = {}
): { valid: boolean; error?: string } => {
  const trimmed = input.trim();

  if (options.min !== undefined && trimmed.length < options.min) {
    return { valid: false, error: `Too short (min ${options.min} chars)` };
  }

  if (options.max !== undefined && trimmed.length > options.max) {
    return { valid: false, error: `Too long (max ${options.max} chars)` };
  }

  if (options.pattern && !options.pattern.test(trimmed)) {
    return { valid: false, error: "Contains invalid characters" };
  }

  return { valid: true };
};

export const RATE_LIMITS = {
  AI_REQUESTS_PER_MINUTE: 3,
  MAX_TASK_LENGTH: 100,
  MAX_PROMPT_LENGTH: 200,
  MAX_GUILD_NAME_LENGTH: 20,
};

// Simple rate limiter tracking
export class RateLimiter {
  private static timestamps: number[] = [];

  static canExecute(limit: number, windowMs: number): { allowed: boolean; waitTime?: number } {
    const now = Date.now();
    this.timestamps = this.timestamps.filter(ts => now - ts < windowMs);

    if (this.timestamps.length >= limit) {
      const oldest = this.timestamps[0];
      return { 
        allowed: false, 
        waitTime: Math.ceil((windowMs - (now - oldest)) / 1000) 
      };
    }

    this.timestamps.push(now);
    return { allowed: true };
  }
}

import React, { useState } from 'react';
import { Task } from '../types';
import { sanitizeText, validateString, RATE_LIMITS } from '../utils/security';

interface TodoListProps {
  tasks: Task[];
  setTasks: React.Dispatch<React.SetStateAction<Task[]>>;
  onToggle: (id: string) => void;
  isPartyActive?: boolean;
}

export const TodoList: React.FC<TodoListProps> = ({ tasks, setTasks, onToggle, isPartyActive }) => {
  const [inputValue, setInputValue] = useState('');
  const [isPartyTask, setIsPartyTask] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const addTask = (e?: React.FormEvent) => {
    e?.preventDefault();
    setError(null);

    const validation = validateString(inputValue, { 
      min: 1, 
      max: RATE_LIMITS.MAX_TASK_LENGTH 
    });

    if (!validation.valid) {
      setError(validation.error || 'Invalid input');
      return;
    }

    const sanitized = sanitizeText(inputValue.trim());

    const newTask: Task = {
      id: crypto.randomUUID(), // More secure than Date.now()
      text: sanitized,
      completed: false,
      xp: 25 + Math.floor(Math.random() * 25),
      isPartyQuest: isPartyTask
    };

    setTasks([newTask, ...tasks]);
    setInputValue('');
    setIsPartyTask(false);
  };

  const deleteTask = (id: string) => {
    setTasks(prev => prev.filter(t => t.id !== id));
  };

  return (
    <div className="max-w-2xl mx-auto p-4 md:p-8 space-y-8">
      <div className="text-center space-y-4">
        <h2 className="pixel-font text-2xl text-yellow-400">ACTIVE QUESTS</h2>
