              type="submit"
              className="pixel-button pixel-font text-xs bg-green-500"
            >
              Add
            </button>
          </div>
          {error && <p className="pixel-font text-[8px] text-red-500 uppercase">{error}</p>}
        </div>
        {isPartyActive && (
          <label className="flex items-center gap-2 cursor-pointer">
