import React, { useState } from 'react';
import { GoogleGenAI, Type } from '@google/genai';
import { Task } from '../types';
import { sanitizeText, validateString, RateLimiter, RATE_LIMITS } from '../utils/security';

interface AISuggestionsProps {
  tasks: Task[];
  setTasks: React.Dispatch<React.SetStateAction<Task[]>>;
  isPartyActive?: boolean;
  mana: number;
  onUseMana: (amt: number) => void;
}

export const AISuggestions: React.FC<AISuggestionsProps> = ({ tasks, setTasks, isPartyActive, mana, onUseMana }) => {
  const [prompt, setPrompt] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [suggestion, setSuggestion] = useState<{advice: string; roadmap: string[]} | null>(null);

  const MANA_COST = 20;

  const getHelp = async () => {
    setError(null);

    // 1. Client-side Input Validation
    const validation = validateString(prompt, { 
      min: 5, 
      max: RATE_LIMITS.MAX_PROMPT_LENGTH 
    });

    if (!validation.valid) {
      setError(validation.error || 'Invalid prompt');
      return;
    }

    // 2. Rate Limiting Check
    const rateCheck = RateLimiter.canExecute(RATE_LIMITS.AI_REQUESTS_PER_MINUTE, 60000);
    if (!rateCheck.allowed) {
      setError(`Rate limit reached. Wait ${rateCheck.waitTime}s`);
      return;
    }

    if (mana < MANA_COST) {
      setError('Insufficient Mana');
      return;
    }

    setLoading(true);
    onUseMana(MANA_COST);

    try {
      // 3. Secure API Initialization: Always create a fresh instance
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const sanitizedPrompt = sanitizeText(prompt.trim());

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Study Topic Request: ${sanitizedPrompt}.`,
        config: {
          systemInstruction: `You are the Legendary High-Mage of Pedagogy. Return valid JSON only. advice: mystical tactical summary. roadmap: 5 steps. quests: 3 tasks with title and difficulty_xp (max 500).`,
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              advice: { type: Type.STRING },
              roadmap: { type: Type.ARRAY, items: { type: Type.STRING } },
              quests: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: { 
                    title: { type: Type.STRING }, 
                    difficulty_xp: { type: Type.NUMBER } 
                  },
                  required: ["title", "difficulty_xp"]
                }
              }
            },
            required: ["advice", "roadmap", "quests"]
          }
        }
      });

      // 4. Safe Parsing and Mapping
      const rawText = response.text || "{}";
      const data = JSON.parse(rawText);

      setSuggestion({ 
        advice: sanitizeText(data.advice || "No advice provided."), 
        roadmap: (data.roadmap || []).map((s: string) => sanitizeText(s)) 
      });

      const newTasks: Task[] = (data.quests || []).map((q: any) => ({
        id: crypto.randomUUID(),
        text: sanitizeText(q.title || "AI Quest"),
        completed: false,
        xp: Math.min(500, q.difficulty_xp || 50)
      }));

      setTasks(prev => [...newTasks, ...prev]);
      setPrompt('');
    } catch (err: any) {
      console.error("AI Error:", err);
      setError(err.message?.includes("429") ? "Server busy. Try again later." : "The Sage is silent. Check your connection.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-2xl mx-auto p-4 md:p-8 space-y-8">
      <div className="text-center space-y-4">
        <h2 className="pixel-font text-2xl text-purple-400">THE GREAT LIBRARY</h2>
        <div className="flex justify-center items-center gap-2">
          <span className="text-purple-400 pixel-font text-[10px]">MANA: {mana}/100</span>
          <div className="w-32 h-2 bg-gray-900 border border-black overflow-hidden">
            <div className="h-full bg-purple-500 transition-all" style={{ width: `${mana}%` }}></div>
          </div>
        </div>
      </div>

      <div className={`bg-[#1f2833] pixel-border p-6 flex flex-col gap-4 ${error ? 'border-red-500' : ''}`}>
        <textarea 
          value={prompt}
          onChange={(e) => {
            setPrompt(e.target.value);
            if (error) setError(null);
          }}
          placeholder="What do you want to learn today? (e.g. Ancient History, Quantum Physics)"
          className="w-full h-24 bg-[#0b0c10] border-4 border-black p-4 pixel-font text-[10px] text-white focus:outline-none focus:border-purple-400 resize-none"
          maxLength={RATE_LIMITS.MAX_PROMPT_LENGTH}
        />

        {error && <p className="pixel-font text-[8px] text-red-500 text-center uppercase animate-pulse">{error}</p>}

        <button 
          onClick={getHelp}
          disabled={loading || mana < MANA_COST || prompt.length < 5}
          className={`pixel-button pixel-font text-xs ${loading || mana < MANA_COST || prompt.length < 5 ? 'bg-gray-600 opacity-50' : 'bg-purple-600'}`}
        >
          {loading ? 'SUMMONING...' : mana < MANA_COST ? 'INSUFFICIENT MANA' : `EXPEND ${MANA_COST} MANA`}
        </button>
        <p className="retro-font text-[10px] text-gray-500 text-center uppercase italic">The Sage accepts only serious inquiries. 3 calls per minute.</p>
      </div>

      {suggestion && (
        <div className="bg-[#fefce8] text-black pixel-border p-6 animate-fade-in space-y-4 relative">
          <button 
            onClick={() => setSuggestion(null)} 
            className="absolute top-4 right-4 text-xs font-bold"
            aria-label="Close"
          >
            ✕
          </button>
          <h3 className="pixel-font text-sm uppercase text-purple-800">Sage's Wisdom</h3>
          <p className="retro-font text-xl italic leading-tight">"{suggestion.advice}"</p>
          <div className="bg-black/5 p-4 space-y-2 pixel-border border-black/20">
            {suggestion.roadmap.map((step, i) => (
              <p key={i} className="retro-font text-lg flex gap-2">
                <span className="font-bold">{i+1}.</span> {step}
              </p>
            ))}
          </div>
          <p className="pixel-font text-[8px] text-blue-600 uppercase">✨ Quests have been added to your log!</p>
        </div>
      )}
    </div>
  );
};

